// === DEDUPLICATE v2 - Comparaison multi-criteres + tracabilite (defensif) ===
// Strategies par ordre de priorite :
//   1. DOI identique (strict, high confidence)
//   2. Titre normalise + annee + 1er auteur normalise (strong, medium confidence)
//   3. Titre normalise seul (fallback, low confidence)
//
// Hardening : try/catch global + defensive sur item.json null/undefined.
// Si le code plante, on retourne un item d'erreur structure (au lieu de crasher n8n -> 500).

try {
const items = $input.all();
console.log('[DEDUP v2] Recu ' + items.length + ' items en entree');

// === HELPERS ===
function normalizeTitle(t) {
  return (t || '').toLowerCase()
    .replace(/[^a-z0-9]/g, '')
    .substring(0, 80);
}

function normalizeAuthor(a) {
  if (!a) return '';
  // "Jean Dupont" -> "dupont" ; "Dupont J." -> "dupont" ; ["A. Smith"] -> "smith"
  let s = Array.isArray(a) ? (a[0] || '') : String(a);
  s = s.toLowerCase().replace(/[.,]/g, ' ').trim();
  // Garder le dernier mot (= surname le plus probable)
  const parts = s.split(/\s+/).filter(Boolean);
  return parts.length > 0 ? parts[parts.length - 1] : '';
}

function getYear(item) {
  const y = item.year || item.publication_year || '';
  const m = String(y).match(/\d{4}/);
  return m ? m[0] : '';
}

function getDoi(item) {
  return (item.doi || '').toLowerCase().trim().replace(/^https?:\/\/(dx\.)?doi\.org\//, '');
}

function getSourceTag(item) {
  return (item._source || 'unknown').toLowerCase();
}

// === DEDUP PASSE 1 : DOI strict ===
const seenDOI = new Map();   // doi -> first_index
const seenTitleYearAuthor = new Map();  // key -> first_index
const seenTitleOnly = new Map();  // titleKey -> first_index

const duplicates = [];  // {index, master_index, strategy, confidence}
const masters = [];      // articles uniques gardes

items.forEach((item, idx) => {
  // Hardening : item.json peut etre null/undefined dans des cas tres edge
  const a = (item && item.json) ? item.json : {};
  const doi = getDoi(a);
  const titleNorm = normalizeTitle(a.title);
  const year = getYear(a);
  const firstAuthor = normalizeAuthor(a.authors);
  const tyaKey = titleNorm + '|' + year + '|' + firstAuthor;

  // Strategie 1 : DOI
  if (doi) {
    if (seenDOI.has(doi)) {
      duplicates.push({
        index: idx,
        master_index: seenDOI.get(doi),
        strategy: 'doi',
        confidence: 'high',
        key: doi
      });
      return;
    }
    seenDOI.set(doi, idx);
  }

  // Strategie 2 : titre + annee + auteur (si titre + annee + auteur tous presents)
  if (titleNorm && year && firstAuthor) {
    if (seenTitleYearAuthor.has(tyaKey)) {
      duplicates.push({
        index: idx,
        master_index: seenTitleYearAuthor.get(tyaKey),
        strategy: 'title+year+author',
        confidence: 'medium',
        key: tyaKey
      });
      return;
    }
    seenTitleYearAuthor.set(tyaKey, idx);
  }

  // Strategie 3 : titre normalise seul (fallback faible)
  if (titleNorm && titleNorm.length >= 20) {
    if (seenTitleOnly.has(titleNorm)) {
      duplicates.push({
        index: idx,
        master_index: seenTitleOnly.get(titleNorm),
        strategy: 'title-only',
        confidence: 'low',
        key: titleNorm
      });
      return;
    }
    seenTitleOnly.set(titleNorm, idx);
  }

  // Pas de doublon -> garde l'article
  masters.push({ index: idx, item: item });
});

// === STATISTIQUES ===
const strategies = { doi: 0, 'title+year+author': 0, 'title-only': 0 };
const confidences = { high: 0, medium: 0, low: 0 };
for (const d of duplicates) {
  strategies[d.strategy] = (strategies[d.strategy] || 0) + 1;
  confidences[d.confidence] = (confidences[d.confidence] || 0) + 1;
}

const sourceCounts = {};
for (const m of masters) {
  const src = getSourceTag(m.item.json);
  sourceCounts[src] = (sourceCounts[src] || 0) + 1;
}

console.log('[DEDUP v2] Resultats :');
console.log('  Items entree : ' + items.length);
console.log('  Uniques gardes : ' + masters.length);
console.log('  Doublons supprimes : ' + duplicates.length);
console.log('  Par strategie : doi=' + (strategies.doi||0) + ' tya=' + (strategies['title+year+author']||0) + ' title=' + (strategies['title-only']||0));
console.log('  Par confidence : high=' + (confidences.high||0) + ' medium=' + (confidences.medium||0) + ' low=' + (confidences.low||0));
console.log('  Par source : ' + JSON.stringify(sourceCounts));

// === OUTPUT ===
// Premier item : enrichi avec les stats globales + rapport detaille
// Tous les items : enrichis avec _deduplication_key, _dedup_strategy, _total_before_dedup, _duplicates_removed
const dedupReport = {
  total_input: items.length,
  total_unique: masters.length,
  total_duplicates: duplicates.length,
  dedup_rate_pct: items.length > 0 ? Math.round(duplicates.length * 100 / items.length) : 0,
  strategies: strategies,
  confidences: confidences,
  by_source: sourceCounts,
  // Liste detaillee des doublons detectes (limite 1000 pour eviter explosion JSON)
  duplicates_detail: duplicates.slice(0, 1000).map(d => ({
    duplicate_title: ((items[d.index] && items[d.index].json && items[d.index].json.title) || '').substring(0, 120),
    master_title: ((items[d.master_index] && items[d.master_index].json && items[d.master_index].json.title) || '').substring(0, 120),
    strategy: d.strategy,
    confidence: d.confidence,
    key_excerpt: String(d.key).substring(0, 60)
  }))
};

// Hardening : utilise m.item.json || {} pour eviter crash si jamais null
const firstMasterIdx = masters.length > 0 ? masters[0].index : -1;
return masters.map(m => {
  const src = (m.item && m.item.json) ? m.item.json : {};
  return {
    json: Object.assign({}, src, {
      _deduplication_key: getDoi(src) || normalizeTitle(src.title),
      _total_before_dedup: items.length,
      _duplicates_removed: duplicates.length,
      _dedup_report: m.index === firstMasterIdx ? dedupReport : undefined
    })
  };
});

} catch (err) {
  // Si quoi que ce soit plante dans le code dedup, on retourne un item d'erreur structure
  // au lieu de laisser n8n planter avec HTTP 500. Permet a l'UI d'afficher un message utile.
  console.log('[DEDUP v2] ERREUR FATALE : ' + err.message);
  console.log('[DEDUP v2] Stack : ' + (err.stack || 'N/A'));
  return [{ json: {
    error: 'Dedup v2 plantage : ' + err.message,
    error_stack: (err.stack || '').substring(0, 1000),
    _dedup_failed: true,
    _input_count: (typeof items !== 'undefined' && items) ? items.length : 0
  }}];
}
